// Name the per-result components so we can talk about each conjunct of
// `HostState::next_ensures` without re-binding `let (ok, res) = rc;`
// inside the open-spec body.
let (ok1, ev1) = r1;
let (ok2, ev2) = r2;

let pre_v = pre_self_.view();
let post1_v = post1_self_.view();
let post2_v = post2_self_.view();

// `HostState::next_ensures` is `open spec fn`; Verus can unfold its
// body directly. Re-asserting each of its six conjuncts (once per
// result) gives z3 explicit, identically-shaped trigger terms for both
// runs.
//
// In particular `EventResults::well_typed_events` is itself a
// conjunction of three per-index `forall|i| ... self.{recvs,clocks,
// sends}[i] ...` quantifiers, and they sit behind a top-level
// `well_typed_events(ev1@)` / `well_typed_events(ev2@)` term. When the
// only thing z3 sees is two of those top-level terms with `r1`/`r2`
// substituted, the inner triggers `ev1@.recvs[i]` and `ev2@.recvs[i]`
// never get materialised at the same proof site, so the matching
// instantiations for the determinism goal don't line up.  We pull
// every inner `forall` out explicitly so z3 has both halves of the
// trigger structure side-by-side.

// --- conjunct 1: ok == new_netc.ok() ---
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 == post1_netc.ok()));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 == post2_netc.ok()));

// --- conjunct 2: ok ==> new_self.invariants(&new_netc.my_end_point()) ---
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> post1_self_.invariants(&post1_netc.my_end_point())));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> post2_self_.invariants(&post2_netc.my_end_point())));

// --- conjunct 3: ok ==> Self::next(old_self.view(), new_self.view(), res@.ios) ---
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> HostState::next(pre_v, post1_v, ev1@.ios)));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> HostState::next(pre_v, post2_v, ev2@.ios)));

// --- conjunct 4: ok ==> res@.event_seq() == res@.ios ---
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> (ok1 ==> ev1@.event_seq() == ev1@.ios));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (ok2 ==> ev2@.event_seq() == ev2@.ios));

// --- conjunct 5: (ok || res@.sends.len()>0)
//                  ==> new_netc.history() == old_netc.history() + res@.event_seq() ---
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ((ok1 || ev1@.sends.len() > 0)
        ==> post1_netc.history() == pre_netc.history() + ev1@.event_seq()));
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ((ok2 || ev2@.sends.len() > 0)
        ==> post2_netc.history() == pre_netc.history() + ev2@.event_seq()));

// --- conjunct 6: res@.well_typed_events() ---
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ev1@.well_typed_events());
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ev2@.well_typed_events());

// --- conjunct 6, unfolded: the three per-index `forall` quantifiers
// hidden inside `EventResults::well_typed_events`.  Pulling them out
// explicitly is the trigger-alignment step described in the prompt:
// the term `ev1@.recvs[i]` (resp. clocks / sends) now lives at the
// same proof site as `ev2@.recvs[i]`, so z3 can match them in lockstep
// when discharging the determinism goal.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> forall|i: int| 0 <= i < ev1@.recvs.len() ==> ev1@.recvs[i] is Receive);
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> forall|i: int| 0 <= i < ev2@.recvs.len() ==> ev2@.recvs[i] is Receive);

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> forall|i: int| 0 <= i < ev1@.clocks.len() ==>
        ev1@.clocks[i] is ReadClock || ev1@.clocks[i] is TimeoutReceive);
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> forall|i: int| 0 <= i < ev2@.clocks.len() ==>
        ev2@.clocks[i] is ReadClock || ev2@.clocks[i] is TimeoutReceive);

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> forall|i: int| 0 <= i < ev1@.sends.len() ==> ev1@.sends[i] is Send);
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> forall|i: int| 0 <= i < ev2@.sends.len() ==> ev2@.sends[i] is Send);

assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ev1@.clocks.len() <= 1);
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ev2@.clocks.len() <= 1);

// `event_seq` is `recvs + clocks + sends`. Expose that definition
// concretely for both runs so that the conjunct-5 history equation
// uses the same syntactic shape (a `Seq + Seq + Seq` term) on both
// sides — otherwise z3 is matching `event_seq(ev1@)` vs
// `event_seq(ev2@)` without ever unfolding either.
assert(HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    ==> ev1@.event_seq() == ev1@.recvs + ev1@.clocks + ev1@.sends);
assert(HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> ev2@.event_seq() == ev2@.recvs + ev2@.clocks + ev2@.sends);

// Joint summary: under the joint premise, every per-run fact above
// holds simultaneously.  Asserting this combined conjunction at the
// same proof site is what makes the side-by-side trigger pattern
// available to z3 when it checks the final implication into
// `det_real_next_impl_equal`.
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
    && HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
    ==> (
        (ok1 == post1_netc.ok())
        && (ok2 == post2_netc.ok())
        && (ok1 ==> HostState::next(pre_v, post1_v, ev1@.ios))
        && (ok2 ==> HostState::next(pre_v, post2_v, ev2@.ios))
        && (ok1 ==> ev1@.event_seq() == ev1@.ios)
        && (ok2 ==> ev2@.event_seq() == ev2@.ios)
        && (ev1@.well_typed_events() && ev2@.well_typed_events())
    )
);
